import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

export default function FacultyDashboard() {
  const { user, API } = useAuth();
  const navigate = useNavigate();
  const [projects, setProjects]   = useState([]);
  const [requests, setRequests]   = useState([]);
  const [announcements, setAnnouncements] = useState([]);
  const [loading, setLoading]     = useState(true);
  const [showForm, setShowForm]   = useState(false);
  const [saving, setSaving]       = useState(false);
  const [msg, setMsg]             = useState('');
  const [form, setForm] = useState({ title:'', description:'', requiredSkills:'', duration:'', maxStudents:5 });

  const h = () => ({ headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }, timeout: 15000 });

  const load = async () => {
    setLoading(true);
    try {
      const [pRes, rRes, anRes] = await Promise.all([
        axios.get(`${API}/projects/my`, h()),
        axios.get(`${API}/requests/my`, h()),
        axios.get(`${API}/announcements`, h()),
      ]);
      setProjects(pRes.data);
      setRequests(rRes.data);
      setAnnouncements(anRes.data.slice(0,3));
    } catch {}
    setLoading(false);
  };

  useEffect(() => { load(); }, [API]);

  const handleCreate = async () => {
    if (!form.title.trim() || !form.description.trim()) { setMsg('❌ Title and description required'); return; }
    setSaving(true);
    try {
      await axios.post(`${API}/projects`, {
        ...form,
        requiredSkills: form.requiredSkills.split(',').map(x=>x.trim()).filter(Boolean),
        maxStudents: Number(form.maxStudents)||5,
      }, h());
      setShowForm(false);
      setForm({ title:'', description:'', requiredSkills:'', duration:'', maxStudents:5 });
      setMsg('✅ Project created!');
      setTimeout(()=>setMsg(''),3000);
      load();
    } catch(err) { setMsg('❌ '+(err.response?.data?.message||'Failed')); }
    setSaving(false);
  };

  const handleToggle = async (p) => {
    try {
      const ns = p.status==='open'?'closed':'open';
      await axios.put(`${API}/projects/${p._id}`, { status:ns }, h());
      setProjects(prev=>prev.map(x=>x._id===p._id?{...x,status:ns}:x));
    } catch { alert('Failed'); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this project?')) return;
    try {
      await axios.delete(`${API}/projects/${id}`, h());
      setProjects(prev=>prev.filter(p=>p._id!==id));
    } catch { alert('Failed'); }
  };

  const handleRequest = async (id, status) => {
    try {
      await axios.put(`${API}/requests/${id}`, { status }, h());
      setRequests(prev=>prev.map(r=>r._id===id?{...r,status}:r));
      setMsg(`✅ Application ${status}!`);
      setTimeout(()=>setMsg(''),2000);
    } catch { alert('Failed'); }
  };

  const pending  = requests.filter(r=>r.status==='pending');
  const accepted = requests.filter(r=>r.status==='accepted');
  const totalStudents = projects.reduce((a,p)=>a+(p.acceptedStudents?.length||0),0);

  const stats = [
    { label:'My Projects',    value:projects.length,                            icon:'🗂', color:'#6c63ff' },
    { label:'Open Projects',  value:projects.filter(p=>p.status==='open').length, icon:'✅', color:'#00d4aa' },
    { label:'Pending Requests', value:pending.length,                           icon:'📬', color:'#ffb347' },
    { label:'Total Students', value:totalStudents,                              icon:'🎓', color:'#ff6b9d' },
  ];

  if (loading) return <div style={{padding:'3rem',textAlign:'center',color:'#6c63ff'}}>⏳ Loading...</div>;

  return (
    <div style={{padding:'2rem',maxWidth:1100,margin:'0 auto'}}>

      {/* Header */}
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:'2rem',flexWrap:'wrap',gap:'1rem'}}>
        <div>
          <h1 style={{fontWeight:800,fontSize:'1.75rem',marginBottom:'0.25rem'}}>Welcome, {user.name.split(' ')[0]} 👋</h1>
          <p style={{color:'#9aa3bf'}}>{user.designation||'Faculty'} · {user.department}</p>
        </div>
        <div style={{display:'flex',gap:'0.75rem'}}>
          <button onClick={load} style={{padding:'10px 16px',borderRadius:10,border:'1px solid #252d47',background:'transparent',color:'#9aa3bf',cursor:'pointer',fontSize:'0.875rem'}}>🔄 Refresh</button>
          <button onClick={()=>setShowForm(true)} style={{padding:'10px 20px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',border:'none',borderRadius:10,color:'#fff',fontWeight:700,cursor:'pointer'}}>+ New Project</button>
        </div>
      </div>

      {msg && <div style={{background:msg.includes('✅')?'rgba(74,222,128,0.1)':'rgba(255,87,87,0.1)',border:`1px solid ${msg.includes('✅')?'#4ade8040':'#ff575740'}`,borderRadius:10,padding:'12px',marginBottom:'1rem',color:msg.includes('✅')?'#4ade80':'#ff5757',fontSize:'0.875rem'}}>{msg}</div>}

      {/* Stats */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:'1rem',marginBottom:'2rem'}}>
        {stats.map((s,i)=>(
          <div key={i} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'1.25rem'}}>
            <div style={{fontSize:'1.5rem',marginBottom:'0.5rem'}}>{s.icon}</div>
            <div style={{fontSize:'2rem',fontWeight:800,color:s.color}}>{s.value}</div>
            <div style={{color:'#9aa3bf',fontSize:'0.875rem',marginTop:'0.25rem'}}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Pending Requests — PROMINENT */}
      {pending.length > 0 && (
        <div style={{marginBottom:'2rem'}}>
          <h2 style={{fontWeight:700,fontSize:'1.1rem',marginBottom:'1rem'}}>📬 Pending Applications <span style={{background:'#ff6b9d',color:'#fff',borderRadius:99,padding:'2px 8px',fontSize:'0.75rem',marginLeft:'0.5rem'}}>{pending.length}</span></h2>
          <div style={{display:'flex',flexDirection:'column',gap:'0.75rem'}}>
            {pending.map(r => (
              <div key={r._id} style={{background:'#161c2e',border:'1px solid #ffb34730',borderRadius:14,padding:'1.25rem',display:'flex',alignItems:'center',gap:'1rem',flexWrap:'wrap'}}>
                <div style={{flex:1}}>
                  <div style={{fontWeight:700,fontSize:'0.95rem',color:'#e8eaf0'}}>{r.student?.name}</div>
                  <div style={{color:'#9aa3bf',fontSize:'0.8rem'}}>{r.student?.department} · {r.student?.year}</div>
                  <div style={{color:'#6c63ff',fontSize:'0.8rem',marginTop:'0.2rem'}}>Applied for: <strong>{r.project?.title}</strong></div>
                  {r.coverLetter && <div style={{color:'#5c6580',fontSize:'0.78rem',marginTop:'0.25rem',fontStyle:'italic'}}>"{r.coverLetter?.slice(0,80)}..."</div>}
                </div>
                <div style={{display:'flex',gap:'0.5rem',flexShrink:0}}>
                  <button onClick={()=>navigate(`/projects/${r.project?._id}`)} style={{padding:'7px 12px',borderRadius:8,border:'1px solid #252d47',background:'transparent',color:'#9aa3bf',fontSize:'0.8rem',cursor:'pointer'}}>View Profile</button>
                  <button onClick={()=>handleRequest(r._id,'accepted')} style={{padding:'7px 16px',borderRadius:8,background:'rgba(74,222,128,0.1)',border:'1px solid #4ade8040',color:'#4ade80',fontWeight:700,fontSize:'0.8rem',cursor:'pointer'}}>✓ Accept</button>
                  <button onClick={()=>handleRequest(r._id,'rejected')} style={{padding:'7px 16px',borderRadius:8,background:'rgba(255,87,87,0.1)',border:'1px solid #ff575740',color:'#ff5757',fontWeight:700,fontSize:'0.8rem',cursor:'pointer'}}>✗ Reject</button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Announcements */}
      {announcements.length > 0 && (
        <div style={{marginBottom:'2rem'}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'0.75rem'}}>
            <h2 style={{fontWeight:700,fontSize:'1.1rem'}}>📢 Latest Notices</h2>
            <Link to="/announcements" style={{color:'#6c63ff',fontSize:'0.875rem',fontWeight:600}}>View all →</Link>
          </div>
          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(280px,1fr))',gap:'0.75rem'}}>
            {announcements.map(a=>(
              <div key={a._id} onClick={()=>navigate('/announcements')} style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:12,padding:'1rem',cursor:'pointer'}}>
                <div style={{fontWeight:700,fontSize:'0.875rem',color:'#e8eaf0',marginBottom:'0.25rem'}}>{a.title}</div>
                <div style={{color:'#9aa3bf',fontSize:'0.78rem',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{a.content}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* My Projects */}
      <div>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:'1rem'}}>
          <h2 style={{fontWeight:700,fontSize:'1.1rem'}}>🗂 My Projects</h2>
          <button onClick={()=>setShowForm(true)} style={{padding:'7px 16px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',border:'none',borderRadius:8,color:'#fff',fontWeight:700,cursor:'pointer',fontSize:'0.8rem'}}>+ New</button>
        </div>
        {projects.length===0 ? (
          <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:14,padding:'3rem',textAlign:'center',color:'#5c6580'}}>
            <div style={{fontSize:'2rem',marginBottom:'0.5rem'}}>📭</div>
            <div style={{marginBottom:'0.75rem'}}>No projects yet</div>
            <button onClick={()=>setShowForm(true)} style={{padding:'10px 24px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',border:'none',borderRadius:10,color:'#fff',fontWeight:700,cursor:'pointer'}}>Create Your First Project</button>
          </div>
        ) : (
          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(320px,1fr))',gap:'1rem'}}>
            {projects.map(p=>{
              const projRequests = requests.filter(r=>r.project?._id===p._id);
              const projPending  = projRequests.filter(r=>r.status==='pending').length;
              const projAccepted = projRequests.filter(r=>r.status==='accepted').length;
              return (
                <div key={p._id} style={{background:'#161c2e',border:`1px solid ${p.status==='open'?'#00d4aa30':'#252d47'}`,borderRadius:14,padding:'1.25rem'}}>
                  <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:'0.75rem'}}>
                    <h3 style={{fontWeight:700,fontSize:'0.95rem',color:'#e8eaf0',flex:1,marginRight:'0.5rem'}}>{p.title}</h3>
                    <span style={{padding:'3px 10px',borderRadius:99,fontSize:'0.7rem',fontWeight:700,background:p.status==='open'?'rgba(0,212,170,0.1)':'rgba(255,87,87,0.1)',color:p.status==='open'?'#00d4aa':'#ff5757',border:`1px solid ${p.status==='open'?'#00d4aa40':'#ff575740'}`,flexShrink:0}}>{p.status==='open'?'🟢 Open':'🔴 Closed'}</span>
                  </div>
                  <p style={{color:'#9aa3bf',fontSize:'0.8rem',marginBottom:'0.75rem',lineHeight:1.5}}>{p.description?.slice(0,80)}...</p>

                  {/* Stats row */}
                  <div style={{display:'flex',gap:'1rem',marginBottom:'0.75rem'}}>
                    <div style={{textAlign:'center'}}>
                      <div style={{fontWeight:700,color:'#ffb347',fontSize:'1rem'}}>{projPending}</div>
                      <div style={{color:'#5c6580',fontSize:'0.65rem'}}>Pending</div>
                    </div>
                    <div style={{textAlign:'center'}}>
                      <div style={{fontWeight:700,color:'#4ade80',fontSize:'1rem'}}>{projAccepted}</div>
                      <div style={{color:'#5c6580',fontSize:'0.65rem'}}>Accepted</div>
                    </div>
                    <div style={{textAlign:'center'}}>
                      <div style={{fontWeight:700,color:'#6c63ff',fontSize:'1rem'}}>{p.maxStudents||5}</div>
                      <div style={{color:'#5c6580',fontSize:'0.65rem'}}>Max</div>
                    </div>
                  </div>

                  <div style={{display:'flex',gap:'0.5rem',flexWrap:'wrap'}}>
                    <button onClick={()=>navigate(`/projects/${p._id}`)} style={{padding:'6px 12px',borderRadius:7,background:'rgba(108,99,255,0.1)',border:'1px solid #6c63ff30',color:'#6c63ff',fontSize:'0.75rem',fontWeight:600,cursor:'pointer'}}>Manage</button>
                    <button onClick={()=>handleToggle(p)} style={{padding:'6px 12px',borderRadius:7,background:p.status==='open'?'rgba(255,87,87,0.1)':'rgba(0,212,170,0.1)',border:`1px solid ${p.status==='open'?'#ff575740':'#00d4aa40'}`,color:p.status==='open'?'#ff5757':'#00d4aa',fontSize:'0.75rem',fontWeight:600,cursor:'pointer'}}>
                      {p.status==='open'?'🔴 Close':'🟢 Open'}
                    </button>
                    <button onClick={()=>handleDelete(p._id)} style={{padding:'6px 12px',borderRadius:7,background:'transparent',border:'1px solid #252d47',color:'#9aa3bf',fontSize:'0.75rem',cursor:'pointer'}}>Delete</button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Create Project Modal */}
      {showForm && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.75)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:1000,padding:'1rem'}}>
          <div style={{background:'#161c2e',border:'1px solid #252d47',borderRadius:16,padding:'2rem',width:'100%',maxWidth:520,maxHeight:'90vh',overflowY:'auto'}}>
            <h2 style={{fontWeight:800,marginBottom:'1.5rem'}}>+ Create New Project</h2>
            {[
              {label:'Project Title *', key:'title', placeholder:'e.g. AI-based Crop Disease Detection'},
              {label:'Description *', key:'description', placeholder:'Describe the project goals and tasks...', area:true},
              {label:'Required Skills (comma separated)', key:'requiredSkills', placeholder:'e.g. Python, Machine Learning, OpenCV'},
              {label:'Duration', key:'duration', placeholder:'e.g. 3 months'},
            ].map(f=>(
              <div key={f.key} style={{marginBottom:'1rem'}}>
                <label style={{display:'block',marginBottom:'6px',fontSize:'0.875rem',fontWeight:600,color:'#9aa3bf'}}>{f.label}</label>
                {f.area
                  ? <textarea value={form[f.key]} onChange={e=>setForm(x=>({...x,[f.key]:e.target.value}))} placeholder={f.placeholder} rows={3} style={inputStyle} />
                  : <input value={form[f.key]} onChange={e=>setForm(x=>({...x,[f.key]:e.target.value}))} placeholder={f.placeholder} style={inputStyle} />
                }
              </div>
            ))}
            <div style={{marginBottom:'1.5rem'}}>
              <label style={{display:'block',marginBottom:'6px',fontSize:'0.875rem',fontWeight:600,color:'#9aa3bf'}}>Max Students</label>
              <input type="number" min={1} max={20} value={form.maxStudents} onChange={e=>setForm(x=>({...x,maxStudents:e.target.value}))} style={inputStyle} />
            </div>
            <div style={{display:'flex',gap:'0.75rem'}}>
              <button onClick={()=>setShowForm(false)} style={{flex:1,padding:'12px',background:'transparent',border:'1px solid #252d47',borderRadius:10,color:'#9aa3bf',fontWeight:600,cursor:'pointer'}}>Cancel</button>
              <button onClick={handleCreate} disabled={saving} style={{flex:2,padding:'12px',background:'linear-gradient(135deg,#6c63ff,#8b85ff)',border:'none',borderRadius:10,color:'#fff',fontWeight:700,cursor:'pointer'}}>
                {saving?'Creating...':'Create Project'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
const inputStyle = {width:'100%',padding:'10px 14px',background:'#0f1320',border:'1px solid #252d47',borderRadius:8,color:'#e8eaf0',fontSize:'0.9rem',outline:'none',boxSizing:'border-box',resize:'vertical'};
